/**
 * Lensing ring texture:
 * - Center: fully transparent (will be blocked by the black sphere naturally)
 * - Inner fade: subtle orange inner glow
 * - Photon ring: bright white-gold annulus at ~66% radius
 * - Outer: purple/blue lensing haze fading out
 */
function createLensingRingTexture(): THREE.CanvasTexture {
  const S = 512;
  const canvas = document.createElement('canvas');
  canvas.width = S; canvas.height = S;
  const ctx = canvas.getContext('2d')!;
  const c = S / 2;
  ctx.clearRect(0, 0, S, S);

  // === Layer 1: outer lensing haze (purple/violet) ===
  const haze = ctx.createRadialGradient(c, c, c * 0.58, c, c, c * 0.98);
  haze.addColorStop(0.00, 'rgba(0,0,0,0)');
  haze.addColorStop(0.15, 'rgba(120, 70, 255, 0.18)');
  haze.addColorStop(0.50, 'rgba(100, 55, 220, 0.10)');
  haze.addColorStop(1.00, 'rgba(0,0,0,0)');
  ctx.fillStyle = haze;
  ctx.fillRect(0, 0, S, S);

  // === Layer 2: photon ring (bright gold annulus) ===
  const rInner = c * 0.62;
  const rOuter = c * 0.72;
  const photon = ctx.createRadialGradient(c, c, rInner, c, c, rOuter);
  photon.addColorStop(0.00, 'rgba(255, 200, 100, 0.0)');
  photon.addColorStop(0.25, 'rgba(255, 235, 160, 0.85)');
  photon.addColorStop(0.50, 'rgba(255, 255, 230, 1.00)');
  photon.addColorStop(0.75, 'rgba(255, 220, 140, 0.85)');
  photon.addColorStop(1.00, 'rgba(255, 160,  60, 0.0)');
  ctx.fillStyle = photon;
  ctx.beginPath();
  ctx.arc(c, c, rOuter + 4, 0, Math.PI * 2);
  ctx.arc(c, c, rInner - 4, 0, Math.PI * 2, true);
