"// ─── Black Hole canvas textures ──────────────────────────────────────────────

/** Photon ring: dark center + bright ring at ~65% radius + outer fade */
function createPhotonRingTexture(): THREE.CanvasTexture {
  const S = 512;
  const canvas = document.createElement('canvas');
  canvas.width = S; canvas.height = S;
  const ctx = canvas.getContext('2d')!;
  const c = S / 2;

  // Transparent fill
  ctx.clearRect(0, 0, S, S);

  // Outer diffuse lensing haze
  const haze = ctx.createRadialGradient(c, c, c * 0.55, c, c, c);
  haze.addColorStop(0.0, 'rgba(120, 80, 255, 0.0)');
  haze.addColorStop(0.4, 'rgba(140, 90, 255, 0.25)');
  haze.addColorStop(0.7, 'rgba(100, 60, 200, 0.12)');
  haze.addColorStop(1.0, 'rgba(0,0,0,0)');
  ctx.fillStyle = haze;
  ctx.fillRect(0, 0, S, S);

  // Photon ring (bright annulus)
  const ringR = c * 0.68;
  const ringW = c * 0.055;
  const ring = ctx.createRadialGradient(c, c, ringR - ringW, c, c, ringR + ringW);
  ring.addColorStop(0.0,  'rgba(255,230,160,0)');
  ring.addColorStop(0.35, 'rgba(255,240,180,0.9)');
  ring.addColorStop(0.50, 'rgba(255,255,220,1.0)');
  ring.addColorStop(0.65, 'rgba(255,230,160,0.9)');
  ring.addColorStop(1.0,  'rgba(255,200,100,0)');
  ctx.fillStyle = ring;
  ctx.beginPath();
  ctx.arc(c, c, ringR + ringW * 1.5, 0, Math.PI * 2);
  ctx.arc(c, c, ringR - ringW * 1.5, 0, Math.PI * 2, true);
  ctx.fill();

  // Inner glow just inside photon ring
  const inner = ctx.createRadialGradient(c, c, 0, c, c, ringR - ringW);
  inner.addColorStop(0.0,  'rgba(255,160,60,0.0)');
  inner.addColorStop(0.75, 'rgba(255,120,40,0.35)');
  inner.addColorStop(1.0,  'rgba(255,160,80,0.0)');
  ctx.fillStyle = inner;
  ctx.beginPath();
  ctx.arc(c, c, ringR - ringW, 0, Math.PI * 2);
  ctx.fill();

  return new THREE.CanvasTexture(canvas);
}



